+//! bmap — Control Bluetooth audio devices over the BMAP protocol.
+//!
+//! # Example
+//!
+//! ```no_run
+//! use bmap::{connect, devices};
+//!
+//! let dev = connect(None, "qc_ultra2").unwrap();
+//! println!("Battery: {}%", dev.battery().unwrap());
